query:
-- Phase 1: Land items - lump sum month 1
UPDATE cost_distribution_rules SET phase_start_month=1, phase_end_month=1, payment_schedule_json='[{"month":1,"pct":100}]' WHERE primary_phase='land';

-- Phase 2: Design items
-- Soil test, survey: month 1 lump sum
UPDATE cost_distribution_rules SET phase_start_month=1, phase_end_month=1, payment_schedule_json='[{"month":1,"pct":100}]' WHERE item_key IN ('soil_test','topographic_survey');
-- Design fees: spread equally (default: 30% month1, 30% month2, 40% month3 of design phase)
UPDATE cost_distribution_rules SET phase_start_month=1, phase_end_month=NULL, payment_schedule_json='[{"month":1,"pct":30},{"month":2,"pct":30},{"month":3,"pct":40}]' WHERE item_key='design_fees';
-- Developer fees design portion: spread over design phase
UPDATE cost_distribution_rules SET phase_start_month=1, phase_end_month=NULL, payment_schedule_json='[{"month":1,"pct":50},{"month":2,"pct":50}]' WHERE item_key='developer_fees_design';
-- Community fees design: month 1
UPDATE cost_distribution_rules SET phase_start_month=1, phase_end_month=1, payment_schedule_json='[{"month":1,"pct":100}]' WHERE item_key='community_fees_design';
-- Government fees design (10%): month 1
UPDATE cost_distribution_rules SET phase_start_month=1, phase_end_month=1, payment_schedule_json='[{"month":1,"pct":100}]' WHERE item_key='govt_fees_design';

-- Phase 3: Off-plan items - mostly month 1
UPDATE cost_distribution_rules SET phase_start_month=1, phase_end_month=1, payment_schedule_json='[{"month":1,"pct":100}]' WHERE primary_phase='offplan' AND item_key NOT IN ('escrow_deposit','developer_fees_offplan','marketing_offplan');
-- Escrow deposit: month 2
UPDATE cost_distribution_rules SET phase_start_month=2, phase_end_month=2, payment_schedule_json='[{"month":2,"pct":100}]' WHERE item_key='escrow_deposit';
-- Developer fees offplan: month 1
UPDATE cost_distribution_rules SET phase_start_month=1, phase_end_month=1, payment_schedule_json='[{"month":1,"pct":100}]' WHERE item_key='developer_fees_offplan';
-- Marketing offplan (25%): spread over offplan
UPDATE cost_distribution_rules SET phase_start_month=1, phase_end_month=NULL, payment_schedule_json='[{"month":1,"pct":50},{"month":2,"pct":50}]' WHERE item_key='marketing_offplan';

-- Phase 4: Construction items
-- Contractor advance (10%): month 1
UPDATE cost_distribution_rules SET phase_start_month=1, phase_end_month=1, payment_schedule_json='[{"month":1,"pct":100}]' WHERE item_key='contractor_advance';
-- Contingency: spread equally over construction
UPDATE cost_distribution_rules SET phase_start_month=1, phase_end_month=NULL, payment_schedule_json='[{"month":1,"pct":25},{"month":4,"pct":25},{"month":8,"pct":25},{"month":12,"pct":25}]' WHERE item_key='contingency';
-- Govt fees construction (90%): month 3
UPDATE cost_distribution_rules SET phase_start_month=3, phase_end_month=3, payment_schedule_json='[{"month":3,"pct":100}]' WHERE item_key='govt_fees_construction';
-- Contractor remaining (70% escrow): spread equally over construction
UPDATE cost_distribution_rules SET phase_start_month=1, phase_end_month=NULL, payment_schedule_json='[{"month":1,"pct":10},{"month":3,"pct":15},{"month":6,"pct":15},{"month":9,"pct":15},{"month":12,"pct":15},{"month":15,"pct":15},{"month":18,"pct":15}]' WHERE item_key='contractor_remaining';
-- Supervision fees: spread equally
UPDATE cost_distribution_rules SET phase_start_month=1, phase_end_month=NULL, payment_schedule_json='[{"month":1,"pct":25},{"month":6,"pct":25},{"month":12,"pct":25},{"month":18,"pct":25}]' WHERE item_key='supervision_fees';
-- Sales commission: linked to sales milestones
UPDATE cost_distribution_rules SET phase_start_month=1, phase_end_month=NULL, payment_schedule_json='[{"month":1,"pct":20},{"month":3,"pct":20},{"month":6,"pct":20},{"month":9,"pct":20},{"month":12,"pct":20}]' WHERE item_key='sales_commission';
-- RERA audit reports: every 3 months
UPDATE cost_distribution_rules SET phase_start_month=3, phase_end_month=NULL, payment_schedule_json='[{"month":3,"pct":25},{"month":6,"pct":25},{"month":9,"pct":25},{"month":12,"pct":25}]' WHERE item_key='rera_audit_reports';
-- RERA inspection reports: every 3 months
UPDATE cost_distribution_rules SET phase_start_month=3, phase_end_month=NULL, payment_schedule_json='[{"month":3,"pct":25},{"month":6,"pct":25},{"month":9,"pct":25},{"month":12,"pct":25}]' WHERE item_key='rera_inspection_reports';
-- Developer fees construction: spread
UPDATE cost_distribution_rules SET phase_start_month=1, phase_end_month=NULL, payment_schedule_json='[{"month":1,"pct":20},{"month":4,"pct":20},{"month":8,"pct":20},{"month":12,"pct":20},{"month":16,"pct":20}]' WHERE item_key='developer_fees_construction';
-- Marketing construction: spread
UPDATE cost_distribution_rules SET phase_start_month=1, phase_end_month=NULL, payment_schedule_json='[{"month":1,"pct":25},{"month":2,"pct":25},{"month":3,"pct":25},{"month":4,"pct":25}]' WHERE item_key='marketing_construction';
-- Community fees construction: month 1
UPDATE cost_distribution_rules SET phase_start_month=1, phase_end_month=1, payment_schedule_json='[{"month":1,"pct":100}]' WHERE item_key='community_fees_construction';

